import React, { useState, useEffect } from "react";
import "./EditAreaModal.css";
import { canDeleteArea } from "../utils/permissions";
import { API_BASE_URL } from "../config";

export default function EditAreaModal({ area, onClose, onUpdate, user }) {
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [type, setType] = useState("rectangle");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [deleting, setDeleting] = useState(false);

  useEffect(() => {
    if (area) {
      setName(area.name || "");
      setDescription(area.description || "");
      setType(area.type || "rectangle");
    }
  }, [area]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    if (!name.trim()) {
      setError("Area name is required");
      return;
    }

    setLoading(true);

    try {
      const response = await fetch(`${API_BASE_URL}/api/areas/${area.id}`, {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
          "x-user": user.username,
          "x-user-id": user.id,
          "x-user-role": user.role,
        },
        body: JSON.stringify({
          name,
          description,
          type,
          bounds_json: area.bounds_json,
          positions: area.positions,
        }),
      });

      if (!response.ok) {
        const data = await response.json();
        setError(data.error || "Failed to update area");
        setLoading(false);
        return;
      }

      setLoading(false);
      onUpdate();
    } catch (err) {
      setError("Connection error: " + err.message);
      setLoading(false);
    }
  };

  const handleDelete = async () => {
    if (
      !window.confirm(
        "Are you sure you want to delete this area? This action cannot be undone and will also delete all plants in this area.",
      )
    ) {
      return;
    }

    setError("");
    setDeleting(true);

    try {
      const response = await fetch(`${API_BASE_URL}/api/areas/${area.id}`, {
        method: "DELETE",
        headers: {
          "x-user": user.username,
          "x-user-id": user.id,
          "x-user-role": user.role,
        },
      });

      if (!response.ok) {
        const data = await response.json();
        setError(data.error || "Failed to delete area");
        setDeleting(false);
        return;
      }

      setDeleting(false);
      onUpdate();
    } catch (err) {
      setError("Connection error: " + err.message);
      setDeleting(false);
    }
  };

  const canDelete = canDeleteArea(user.role, area?.permission);

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content" onClick={(e) => e.stopPropagation()}>
        <div className="modal-header">
          <h3>Edit Area</h3>
          <button className="modal-close" onClick={onClose}>
            <i className="fas fa-times"></i>
          </button>
        </div>

        {error && <div className="error-message">{error}</div>}

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Area Name *</label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              required
            />
          </div>

          <div className="form-group">
            <label>Description</label>
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              rows="3"
            />
          </div>

          <div className="form-group">
            <label>Display Type</label>
            <div className="display-type-badge">
              {area?.photo_display_type === "image"
                ? "🖼️ Image Area"
                : "🗺️ Map Area"}
            </div>
            <small
              style={{ display: "block", marginTop: "5px", color: "#999" }}
            >
              This is immutable. To change the type, create a new area.
            </small>
          </div>

          {area?.photo_display_type === "map" && (
            <div className="form-group">
              <label>Area Type *</label>
              <select value={type} onChange={(e) => setType(e.target.value)}>
                <option value="rectangle">Rectangle</option>
                <option value="polygon">Polygon</option>
              </select>
            </div>
          )}

          <div className="modal-actions">
            {canDelete && (
              <button
                type="button"
                className="btn btn-danger"
                onClick={handleDelete}
                disabled={deleting || loading}
              >
                {deleting ? "Deleting..." : "Delete Area"}
              </button>
            )}
            <button type="button" className="btn btn-cancel" onClick={onClose}>
              Cancel
            </button>
            <button
              type="submit"
              className="btn btn-primary"
              disabled={loading || deleting}
            >
              {loading ? "Updating..." : "Update Area"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
